import base64
from cryptography.fernet import Fernet

def generate_encryption_key():
    key = Fernet.generate_key()
    return key

def encrypt_card_number(card_number, encryption_key):
    cipher_suite = Fernet(encryption_key)
    encrypted_card_number = cipher_suite.encrypt(card_number.encode('utf-8'))
    return base64.b64encode(encrypted_card_number).decode('utf-8')

def decrypt_card_number(encrypted_card_number, encryption_key):
    cipher_suite = Fernet(encryption_key)
    decrypted_card_number = cipher_suite.decrypt(base64.b64decode(encrypted_card_number))
    return decrypted_card_number.decode('utf-8')